import re

# Check for additional CI vs prod mismatches
with open('/Users/[REDACTED]/hc-grc/requirements.txt') as f:
    prod_lines = [l.strip() for l in f if l.strip() and not l.startswith('#')]

with open('/Users/[REDACTED]/hc-grc/requirements-ci.txt') as f:
    ci_lines = [l.strip() for l in f if l.strip() and not l.startswith('#')]

print("=== CI vs PROD VERSION BOUND ANALYSIS ===\n")

# Parse into {package: version_spec}
def parse_spec(line):
    # Handle things like: pkg[extras]>=1.0,<2
    match = re.match(r'([a-zA-Z0-9_-]+)(\[[^\]]+\])?(.*)$', line)
    if match:
        return (match.group(1).lower(), line)
    return None

prod_map = {parse_spec(line)[0]: line for line in prod_lines if parse_spec(line)}
ci_map = {parse_spec(line)[0]: line for line in ci_lines if parse_spec(line)}

overlapping = set(prod_map.keys()) & set(ci_map.keys())

mismatches = []
for pkg in sorted(overlapping):
    prod_spec = prod_map[pkg]
    ci_spec = ci_map[pkg]

    # Extract version bounds
    prod_bounds = re.findall(r'[><=!]+[0-9.]+', prod_spec)
    ci_bounds = re.findall(r'[><=!]+[0-9.]+', ci_spec)

    if prod_spec != ci_spec:
        mismatches.append((pkg, prod_spec, ci_spec, prod_bounds, ci_bounds))

if mismatches:
    print("MISMATCHES (should match per comment #260):\n")
    for pkg, prod, ci, prod_b, ci_b in mismatches:
        print(f"  {pkg}:")
        print(f"    PROD: {prod}")
        print(f"    CI:   {ci}")

        # Check if CI is actually looser
        if prod_b and ci_b:
            prod_floor = min(b for b in prod_b if '>=' in b or '>' in b)
            ci_ceiling = max(b for b in ci_b if '<' in b) if any('<' in b for b in ci_b) else None
            if ci_ceiling:
                print(f"    ⚠ Risk: CI may resolve to versions not tested in PROD")
        print()
else:
    print("✓ All overlapping packages have matching version specs")

